382→
383→        // Every case must have non-empty code, context, and at least one must_find entry
384→        for case in &suite.cases {
385→            assert!(
386→                !case.code.is_empty(),
387→                "code.rs should not be empty for '{}'",
388→                case.name
389→            );
390→            assert!(
391→                !case.context.is_empty(),
392→                "context.md should not be empty for '{}'",
393→                case.name
394→            );
395→            assert!(
396→                !case.expected.must_find.is_empty(),
397→                "must_find should not be empty for '{}'",
398→                case.name
